function s(){const c=new URLSearchParams(window.location.search);if(c.size===0)return;const a=document.querySelector(".userform");a&&c.forEach((t,i)=>{if(["flush","showtemplate","debug","referrer","isDev"].includes(i))return;const n=a.querySelectorAll(`[name="${i}"]`);if(n.length===0)return;const e=n[0];switch(e.type){case"radio":case"checkbox":n.forEach(r=>{r.value===t&&(r.checked=!0,r.dispatchEvent(new Event("change",{bubbles:!0})),window.jQuery&&window.jQuery(r).trigger("change"))});break;case"select-one":case"select-multiple":e.value=t,e.dispatchEvent(new Event("change",{bubbles:!0})),window.jQuery&&window.jQuery(e).trigger("change");break;case"text":case"email":case"tel":case"number":case"date":case"textarea":e.value=decodeURIComponent(t),e.dispatchEvent(new Event("input",{bubbles:!0})),e.dispatchEvent(new Event("change",{bubbles:!0})),window.jQuery&&window.jQuery(e).trigger("input").trigger("change");break;default:e.value=decodeURIComponent(t),e.dispatchEvent(new Event("change",{bubbles:!0})),window.jQuery&&window.jQuery(e).trigger("change")}})}window.addEventListener("load",s);
